# save_face_encode.py
import face_recognition
import cv2
import numpy as np
import base64
import dlib




# Load an image of yourself (make sure it's clear and shows your face)

# Get encodings
def encodings(image_path):
    image = face_recognition.load_image_file(image_path) 
    encodings_list = face_recognition.face_encodings(image)

    if len(encodings_list) == 0:
        return None #no face found

    face_encode = encodings_list[0]
    face_encode_b64 = base64.b64encode(face_encode.tobytes()).decode('utf-8')
    return face_encode_b64




